import{_ as a,c as e,o,a1 as r}from"./chunks/framework.DILC4Csi.js";const b=JSON.parse('{"title":"Bear 整合：自動儲存計畫 | Plannotator","description":"學習 Plannotator 的 Bear 整合設定方法。透過 x-callback-url 自動儲存批准的計畫，智慧產生標籤，實現知識沉澱和計畫歸檔。","frontmatter":{"title":"Bear 整合：自動儲存計畫 | Plannotator","sidebarTitle":"計畫自動存到 Bear","subtitle":"Bear 整合：自動儲存批准的計畫 | Plannotator","description":"學習 Plannotator 的 Bear 整合設定方法。透過 x-callback-url 自動儲存批准的計畫，智慧產生標籤，實現知識沉澱和計畫歸檔。","tags":["整合","Bear","筆記應用程式","知識沉澱"],"prerequisite":["installation-claude-code","platforms-plan-review-basics"],"order":3},"headers":[],"relativePath":"zh-tw/backnotprop/plannotator/advanced/bear-integration/index.md","filePath":"zh-tw/backnotprop/plannotator/advanced/bear-integration/index.md"}'),l={name:"zh-tw/backnotprop/plannotator/advanced/bear-integration/index.md"};function i(n,t,d,s,c,p){return o(),e("div",null,[...t[0]||(t[0]=[r(`<h1 id="bear-整合-自動儲存批准的計畫" tabindex="-1">Bear 整合：自動儲存批准的計畫 <a class="header-anchor" href="#bear-整合-自動儲存批准的計畫" aria-label="Permalink to &quot;Bear 整合：自動儲存批准的計畫&quot;">​</a></h1><h2 id="學完你能做什麼" tabindex="-1">學完你能做什麼 <a class="header-anchor" href="#學完你能做什麼" aria-label="Permalink to &quot;學完你能做什麼&quot;">​</a></h2><p>啟用 Bear 整合後，每次批准計畫時，Plannotator 會自動將計畫儲存到你的 Bear 筆記中，包括：</p><ul><li>自動產生的標題（從計畫擷取）</li><li>智慧標籤（專案名稱、關鍵字、程式語言）</li><li>完整的計畫內容</li></ul><p>這樣你就能在一個地方管理所有批准的計畫，方便後續查閱和知識沉澱。</p><h2 id="你現在的困境" tabindex="-1">你現在的困境 <a class="header-anchor" href="#你現在的困境" aria-label="Permalink to &quot;你現在的困境&quot;">​</a></h2><p>你可能遇到過這些情況：</p><ul><li>AI 產生的計畫很好，但想儲存下來以後參考</li><li>在 Bear 裡手動複製貼上計畫太麻煩</li><li>不同專案的計畫混在一起，沒有標籤管理</li></ul><p>有了 Bear 整合，這些問題都能自動解決。</p><h2 id="什麼時候用這一招" tabindex="-1">什麼時候用這一招 <a class="header-anchor" href="#什麼時候用這一招" aria-label="Permalink to &quot;什麼時候用這一招&quot;">​</a></h2><ul><li>你使用 Bear 做主要筆記應用程式</li><li>需要歸檔批准的計畫做知識庫</li><li>希望透過標籤快速檢索歷史計畫</li></ul><div class="info custom-block"><p class="custom-block-title">關於 Bear</p><p>Bear 是一款 macOS 上的 Markdown 筆記應用程式，支援標籤、加密、同步等功能。如果你還沒安裝，可以造訪 <a href="https://bear.app/" target="_blank" rel="noreferrer">bear.app</a> 了解。</p></div><h2 id="🎒-開始前的準備" tabindex="-1">🎒 開始前的準備 <a class="header-anchor" href="#🎒-開始前的準備" aria-label="Permalink to &quot;🎒 開始前的準備&quot;">​</a></h2><ul><li>已安裝 Plannotator（參見<a href="./../../start/installation-claude-code/">安裝教學</a>）</li><li>已安裝 Bear 並能夠正常使用</li><li>了解基本的計畫審查流程（參見<a href="./../../platforms/plan-review-basics/">計畫審查基礎</a>）</li></ul><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p>Bear 整合的核心是 <strong>x-callback-url</strong> 協定：</p><ol><li>在 Plannotator UI 中啟用 Bear 整合（儲存在瀏覽器 localStorage）</li><li>批准計畫時，Plannotator 發送 <code>bear://x-callback-url/create</code> URL</li><li>系統使用 <code>open</code> 指令自動開啟 Bear 建立筆記</li><li>計畫內容、標題、標籤自動填入</li></ol><p><strong>關鍵特點</strong>：</p><ul><li>無需設定 vault 路徑（不像 Obsidian 需要指定 vault）</li><li>標籤智慧產生（最多 7 個）</li><li>批准計畫時自動儲存</li></ul><div class="tip custom-block"><p class="custom-block-title">與 Obsidian 的區別</p><p>Bear 整合更簡單，不需要設定 vault 路徑，只需一個開關。但 Obsidian 可以指定儲存資料夾和更多客製化。</p></div><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-開啟-plannotator-設定" tabindex="-1">第 1 步：開啟 Plannotator 設定 <a class="header-anchor" href="#第-1-步-開啟-plannotator-設定" aria-label="Permalink to &quot;第 1 步：開啟 Plannotator 設定&quot;">​</a></h3><p>當 AI Agent 產生計畫並開啟 Plannotator UI 後，點擊右上角的 ⚙️ <strong>Settings</strong> 按鈕。</p><p><strong>你應該看到</strong>：設定面板彈出，包含多個設定選項</p><h3 id="第-2-步-啟用-bear-整合" tabindex="-1">第 2 步：啟用 Bear 整合 <a class="header-anchor" href="#第-2-步-啟用-bear-整合" aria-label="Permalink to &quot;第 2 步：啟用 Bear 整合&quot;">​</a></h3><p>在設定面板中找到 <strong>Bear Notes</strong> 部分，點擊開關按鈕。</p><p><strong>為什麼</strong> 開關會從灰色（停用）變為藍色（啟用），同時儲存到瀏覽器的 localStorage 中。</p><p><strong>你應該看到</strong>：</p><ul><li>Bear Notes 開關變藍</li><li>描述文字：「Auto-save approved plans to Bear」</li></ul><h3 id="第-3-步-批准計畫" tabindex="-1">第 3 步：批准計畫 <a class="header-anchor" href="#第-3-步-批准計畫" aria-label="Permalink to &quot;第 3 步：批准計畫&quot;">​</a></h3><p>完成計畫審查後，點擊底部的 <strong>Approve</strong> 按鈕。</p><p><strong>為什麼</strong> Plannotator 會讀取 Bear 設定，如果已啟用，會在批准的同時呼叫 Bear 的 x-callback-url。</p><p><strong>你應該看到</strong>：</p><ul><li>Bear 應用程式自動開啟</li><li>新建筆記視窗彈出</li><li>標題和內容已自動填充</li><li>標籤已自動產生（以 <code>#</code> 開頭）</li></ul><h3 id="第-4-步-檢視儲存的筆記" tabindex="-1">第 4 步：檢視儲存的筆記 <a class="header-anchor" href="#第-4-步-檢視儲存的筆記" aria-label="Permalink to &quot;第 4 步：檢視儲存的筆記&quot;">​</a></h3><p>在 Bear 中，檢查新建的筆記，確認：</p><ul><li>標題是否正確（來自計畫的 H1）</li><li>內容是否完整（包含計畫全文）</li><li>標籤是否合理（專案名稱、關鍵字、程式語言）</li></ul><p><strong>你應該看到</strong>： 類似這樣的筆記結構：</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## User Authentication</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#032F62;--shiki-light-text-decoration:underline;--shiki-dark:#DBEDFF;--shiki-dark-text-decoration:underline;">完整的計畫內容...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">#plannotator #myproject #authentication #typescript #api</span></span></code></pre></div><h2 id="檢查點-✅" tabindex="-1">檢查點 ✅ <a class="header-anchor" href="#檢查點-✅" aria-label="Permalink to &quot;檢查點 ✅&quot;">​</a></h2><ul><li>[ ] Settings 中 Bear Notes 開關已啟用</li><li>[ ] 批准計畫後 Bear 自動開啟</li><li>[ ] 筆記標題與計畫的 H1 一致</li><li>[ ] 筆記包含完整的計畫內容</li><li>[ ] 標籤包含 <code>#plannotator</code> 和專案名稱</li></ul><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><h3 id="bear-沒有自動開啟" tabindex="-1">Bear 沒有自動開啟 <a class="header-anchor" href="#bear-沒有自動開啟" aria-label="Permalink to &quot;Bear 沒有自動開啟&quot;">​</a></h3><p><strong>原因</strong>：系統 <code>open</code> 指令失敗，可能是：</p><ul><li>Bear 未安裝或未從 App Store 下載</li><li>Bear 的 URL scheme 被其他應用程式劫持</li></ul><p><strong>解決方法</strong>：</p><ol><li>確認 Bear 已正常安裝</li><li>在終端機中手動測試：<code>open &quot;bear://x-callback-url/create?title=test&quot;</code></li></ol><h3 id="標籤不符合預期" tabindex="-1">標籤不符合預期 <a class="header-anchor" href="#標籤不符合預期" aria-label="Permalink to &quot;標籤不符合預期&quot;">​</a></h3><p><strong>原因</strong>：標籤是自動產生的，規則如下：</p><ul><li>必選：<code>#plannotator</code></li><li>必選：專案名稱（從 git 儲存庫名稱或目錄名稱擷取）</li><li>可選：從 H1 標題擷取最多 3 個關鍵字（排除停用詞）</li><li>可選：從程式碼區塊擷取程式語言標籤（排除 json/yaml/markdown）</li><li>最多 7 個標籤</li></ul><p><strong>解決方法</strong>：</p><ul><li>標籤不符合預期時，可以在 Bear 中手動編輯</li><li>如果專案名稱不對，檢查 git 儲存庫設定或目錄名稱</li></ul><h3 id="批准但沒有儲存" tabindex="-1">批准但沒有儲存 <a class="header-anchor" href="#批准但沒有儲存" aria-label="Permalink to &quot;批准但沒有儲存&quot;">​</a></h3><p><strong>原因</strong>：</p><ul><li>Bear 開關未啟用（檢查 Settings）</li><li>網路錯誤或 Bear 回應逾時</li><li>計畫內容為空</li></ul><p><strong>解決方法</strong>：</p><ol><li>確認 Settings 中開關是藍色（啟用狀態）</li><li>檢視終端機是否有錯誤日誌（<code>[Bear] Save failed:</code>）</li><li>重新批准計畫</li></ol><h2 id="標籤產生機制詳解" tabindex="-1">標籤產生機制詳解 <a class="header-anchor" href="#標籤產生機制詳解" aria-label="Permalink to &quot;標籤產生機制詳解&quot;">​</a></h2><p>Plannotator 會智慧產生標籤，讓你在 Bear 中快速檢索計畫。以下是標籤的產生規則：</p><table tabindex="0"><thead><tr><th>標籤來源</th><th>範例</th><th>優先順序</th></tr></thead><tbody><tr><td>固定標籤</td><td><code>#plannotator</code></td><td>必選</td></tr><tr><td>專案名稱</td><td><code>#myproject</code>、<code>#plannotator</code></td><td>必選</td></tr><tr><td>H1 關鍵字</td><td><code>#authentication</code>、<code>#api</code></td><td>可選（最多 3 個）</td></tr><tr><td>程式語言</td><td><code>#typescript</code>、<code>#python</code></td><td>可選</td></tr></tbody></table><p><strong>停用詞清單</strong>（不會作為標籤）：</p><ul><li><code>the</code>, <code>and</code>, <code>for</code>, <code>with</code>, <code>this</code>, <code>that</code>, <code>from</code>, <code>into</code></li><li><code>plan</code>, <code>implementation</code>, <code>overview</code>, <code>phase</code>, <code>step</code>, <code>steps</code></li></ul><p><strong>程式語言排除</strong>（不會作為標籤）：</p><ul><li><code>json</code>, <code>yaml</code>, <code>yml</code>, <code>text</code>, <code>txt</code>, <code>markdown</code>, <code>md</code></li></ul><details class="details custom-block"><summary>範例：標籤產生過程</summary><p>假設計畫標題為「Implementation Plan: User Authentication System in TypeScript」，程式碼區塊包含 Python 和 JSON：</p><ol><li><strong>固定標籤</strong>：<code>#plannotator</code></li><li><strong>專案名稱</strong>：<code>#myproject</code>（假設 git 儲存庫名稱）</li><li><strong>H1 關鍵字</strong>： <ul><li><code>implementation</code> → 排除（停用詞）</li><li><code>plan</code> → 排除（停用詞）</li><li><code>user</code> → 保留 → <code>#user</code></li><li><code>authentication</code> → 保留 → <code>#authentication</code></li><li><code>system</code> → 保留 → <code>#system</code></li><li><code>typescript</code> → 保留 → <code>#typescript</code></li></ul></li><li><strong>程式語言</strong>： <ul><li><code>python</code> → 保留 → <code>#python</code></li><li><code>json</code> → 排除（排除清單）</li></ul></li></ol><p>最終標籤：<code>#plannotator #myproject #user #authentication #system #typescript #python</code>（7 個，達到上限）</p></details><h2 id="與-obsidian-整合對比" tabindex="-1">與 Obsidian 整合對比 <a class="header-anchor" href="#與-obsidian-整合對比" aria-label="Permalink to &quot;與 Obsidian 整合對比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>特性</th><th>Bear 整合</th><th>Obsidian 整合</th></tr></thead><tbody><tr><td>設定複雜度</td><td>簡單（僅開關）</td><td>中等（需要選擇 vault 和資料夾）</td></tr><tr><td>儲存位置</td><td>Bear 應用程式內</td><td>指定 vault 路徑</td></tr><tr><td>檔案名稱</td><td>Bear 自動管理</td><td><code>Title - Mon D, YYYY H-MMam.md</code></td></tr><tr><td>Frontmatter</td><td>無（Bear 不支援）</td><td>有（created, source, tags）</td></tr><tr><td>跨平台</td><td>僅 macOS</td><td>macOS/Windows/Linux</td></tr><tr><td>x-callback-url</td><td>✅ 使用</td><td>❌ 直接寫入檔案</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">如何選擇</p><ul><li>如果你只用 macOS 且喜歡 Bear：Bear 整合更簡單</li><li>如果需要跨平台或自訂儲存路徑：Obsidian 整合更靈活</li><li>如果兩者都想用：可以同時啟用（批准計畫會同時儲存到兩個地方）</li></ul></div><h2 id="本課小結" tabindex="-1">本課小結 <a class="header-anchor" href="#本課小結" aria-label="Permalink to &quot;本課小結&quot;">​</a></h2><ul><li>Bear 整合透過 x-callback-url 協定運作，設定簡單</li><li>只需在 Settings 中開啟開關，無需指定路徑</li><li>批准計畫時自動儲存到 Bear</li><li>標籤智慧產生，包含專案名稱、關鍵字、程式語言（最多 7 個）</li><li>與 Obsidian 整合相比，Bear 更簡單但功能較少</li></ul><h2 id="下一課預告" tabindex="-1">下一課預告 <a class="header-anchor" href="#下一課預告" aria-label="Permalink to &quot;下一課預告&quot;">​</a></h2><blockquote><p>下一課我們學習 <strong><a href="./../remote-mode/">遠端/Devcontainer 模式</a></strong>。</p><p>你會學到：</p><ul><li>如何在遠端環境（SSH、devcontainer、WSL）中使用 Plannotator</li><li>設定固定連接埠和連接埠轉發</li><li>在遠端環境中開啟瀏覽器檢視審查頁面</li></ul></blockquote><hr><h2 id="附錄-原始碼參考" tabindex="-1">附錄：原始碼參考 <a class="header-anchor" href="#附錄-原始碼參考" aria-label="Permalink to &quot;附錄：原始碼參考&quot;">​</a></h2><details><summary><strong>點擊展開檢視原始碼位置</strong></summary><blockquote><p>更新時間：2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>檔案路徑</th><th>行號</th></tr></thead><tbody><tr><td>Bear 設定介面</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L18-L20" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>18-20</td></tr><tr><td>儲存到 Bear</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L234-L257" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>234-257</td></tr><tr><td>標籤擷取</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L34-L74" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>34-74</td></tr><tr><td>標題擷取</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L94-L105" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>94-105</td></tr><tr><td>Bear 設定介面</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/bear.ts#L15-L17" target="_blank" rel="noreferrer"><code>packages/ui/utils/bear.ts</code></a></td><td>15-17</td></tr><tr><td>讀取 Bear 設定</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/bear.ts#L22-L26" target="_blank" rel="noreferrer"><code>packages/ui/utils/bear.ts</code></a></td><td>22-26</td></tr><tr><td>儲存 Bear 設定</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/bear.ts#L31-L33" target="_blank" rel="noreferrer"><code>packages/ui/utils/bear.ts</code></a></td><td>31-33</td></tr><tr><td>UI 設定元件</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/Settings.tsx#L496-L518" target="_blank" rel="noreferrer"><code>packages/ui/components/Settings.tsx</code></a></td><td>496-518</td></tr><tr><td>批准時呼叫 Bear</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/editor/App.tsx#L512-L514" target="_blank" rel="noreferrer"><code>packages/editor/App.tsx</code></a></td><td>512-514</td></tr><tr><td>伺服器處理 Bear</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L250-L257" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>250-257</td></tr></tbody></table><p><strong>關鍵函式</strong>：</p><ul><li><code>saveToBear(config: BearConfig)</code>：透過 x-callback-url 將計畫儲存到 Bear</li><li><code>extractTags(markdown: string)</code>：從計畫內容智慧擷取標籤（最多 7 個）</li><li><code>extractTitle(markdown: string)</code>：從計畫的 H1 標題擷取筆記標題</li><li><code>getBearSettings()</code>：從 localStorage 讀取 Bear 整合設定</li><li><code>saveBearSettings(settings)</code>：將 Bear 整合設定儲存到 localStorage</li></ul><p><strong>關鍵常數</strong>：</p><ul><li><code>STORAGE_KEY_ENABLED = &#39;plannotator-bear-enabled&#39;</code>：localStorage 中 Bear 設定的鍵名</li></ul><p><strong>Bear URL 格式</strong>：</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bear</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//x-callback-url/create?title={title}&amp;text={content}&amp;open_note=no</span></span></code></pre></div></details>`,75)])])}const u=a(l,[["render",i]]);export{b as __pageData,u as default};
